  scwin.f_getEverMngLine = async function(line){

  	ds_everlineInfo.removeAll();
  	sbm_everlineInfo.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=NcallCommonEBC"+
  	                      	 "&queryId=retrieveEverMngLine"+
  	                     	 "&param1="+line;

    await $c.sbm.execute(sbm_everlineInfo);
  };

