  scwin.retrieveInspCntrInfo = async function(sVal){
  	ds_inspCntrInfo.removeAll()
  	sbm_inspCntrInfo.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=NcallCommonEBC"+
  	                      	 "&queryId=retrieveInspCntrInfo"+
  	                     	 "&param1="+lc_wrkPlCd.BindColVal+"&param2="+sVal;
  	 await $c.sbm.execute(sbm_inspCntrInfo);

  };

  //-------------------------------------------------
